    NotSerializableShouldBeMocked deepStub2 = mock(ToBeDeepStubbed.class, RETURNS_DEEP_STUBS).getSomething();
    assertThat(deepStub1).isNotNull();
    assertThat(deepStub2).isNotNull();
}

